/**
 * Canonical Explanation Types
 * 
 * Single source of truth for program/session explanation metadata.
 * These types are used by the generator to produce explanations,
 * and by the UI to render them truthfully.
 * 
 * CRITICAL: Every explanation must be grounded in real engine data.
 * Do NOT add explanation text that cannot be derived from reason codes.
 */

// =============================================================================
// REASON CODES - Machine-readable, generated by real engine decisions
// =============================================================================

/**
 * Program-level reason codes explaining why the program was structured this way.
 * Each code corresponds to a specific engine decision point.
 */
export type ProgramReasonCode =
  // Goal-related
  | 'primary_goal_direct'           // Exercise directly trains primary goal
  | 'secondary_goal_support'        // Exercise supports secondary goal
  // Weak point / limiter
  | 'weak_point_support'            // Added to address detected weak point
  | 'limiter_support'               // Added to address skill limiter
  // Progression state
  | 'progression_advance'           // Ready to progress based on performance
  | 'progression_hold'              // Maintaining current level
  | 'progression_regress'           // Stepping back for recovery/technique
  // Fatigue / recovery
  | 'fatigue_high_reduce_volume'    // High fatigue detected, volume reduced
  | 'fatigue_moderate_maintain'     // Moderate fatigue, maintaining load
  | 'fatigue_stable'                // Fatigue under control
  | 'recovery_bias_session'         // Session designed for active recovery
  // Flexible scheduling
  | 'flexible_frequency_contract'   // Reduced days this week
  | 'flexible_frequency_expand'     // Added days this week
  | 'flexible_frequency_maintain'   // Keeping current frequency
  | 'static_schedule_locked'        // User chose fixed schedule
  // Movement intelligence
  | 'joint_stress_downrank'         // Exercise downranked due to joint stress
  | 'straight_arm_load_control'     // Managing straight-arm volume
  | 'bent_arm_balance'              // Balancing bent-arm work
  // Pattern support
  | 'vertical_push_support'         // Vertical pressing for goal support
  | 'horizontal_push_support'       // Horizontal pressing for goal support
  | 'vertical_pull_support'         // Vertical pulling for goal support
  | 'horizontal_pull_support'       // Horizontal pulling for goal support
  | 'straight_arm_pull_support'     // Straight-arm pulling (FL work)
  | 'straight_arm_push_support'     // Straight-arm pushing (planche work)
  | 'compression_support'           // Compression strength for L-sit/V-sit
  | 'anti_extension_support'        // Anti-extension for lever/dragon flag
  | 'scapular_control_support'      // Scapular work for skill stability
  // Session structure
  | 'high_neural_session'           // Primary skill/strength focus
  | 'lower_fatigue_session'         // Lighter load to preserve recovery
  | 'skill_transfer_priority'       // Exercises chosen for skill carryover
  | 'time_budget_constraint'        // Limited by session time
  | 'equipment_constraint'          // Limited by available equipment
  // Stability reasons
  | 'no_change_stability'           // Program stable, no changes needed
  | 'no_progress_incomplete_data'   // Not enough data to progress
  | 'consistency_maintained'        // Keeping consistent structure

/**
 * Session-level reason codes for individual workout explanations
 */
export type SessionReasonCode =
  | 'skill_primary_day'             // Primary skill work day
  | 'strength_primary_day'          // Primary strength work day
  | 'balanced_session'              // Mix of skill and strength
  | 'recovery_active_day'           // Active recovery session
  | 'volume_reduced_fatigue'        // Volume cut due to fatigue
  | 'intensity_preserved'           // Kept intensity, reduced volume
  | 'exercise_swap_equipment'       // Exercise swapped for equipment
  | 'exercise_swap_progression'     // Exercise swapped for progression
  | 'support_limiter_specific'      // Support work for specific limiter
  | 'core_compression_included'     // Compression core added
  | 'core_anti_extension_included'  // Anti-extension core added
  | 'deload_session'                // Deload week session
  | 'comeback_reduced'              // Reduced load after break

/**
 * Change reason codes for comparing versions
 */
export type ChangeReasonCode =
  | 'first_generation'              // Initial program, no comparison
  | 'fatigue_adjustment'            // Changed due to fatigue state
  | 'limiter_shifted'               // Primary limiter changed
  | 'schedule_contracted'           // Fewer days this week
  | 'schedule_expanded'             // More days this week
  | 'progression_updated'           // Exercise progressions changed
  | 'joint_stress_adjustment'       // Joint stress concerns addressed
  | 'feedback_driven'               // Changed based on workout feedback
  | 'no_change_required'            // Program kept same deliberately
  | 'stability_maintained'          // Stable performance, no change

// =============================================================================
// EXPLANATION METADATA STRUCTURES
// =============================================================================

/**
 * Exercise-level explanation attached to each selected exercise
 */
export interface ExerciseExplanation {
  exerciseId: string
  displayName: string
  reasonCodes: ProgramReasonCode[]
  shortReason: string | null  // Resolved from reason codes, null if not yet resolved
}

/**
 * Session/day-level explanation
 */
export interface SessionExplanation {
  dayKey: string              // e.g., "day_1"
  dayNumber: number
  title: string               // e.g., "Day 1: Skill Focus"
  primaryIntent: string       // e.g., "Front Lever Development"
  reasonCodes: SessionReasonCode[]
  whyThisDay: string | null   // Short explanation, resolved from codes
  whyLighterOrHeavier?: string
  limiterSupport?: string[]   // Specific limiters addressed
  exerciseExplanations: ExerciseExplanation[]
}

/**
 * Week structure explanation
 */
export interface WeekStructureExplanation {
  currentWeekFrequency: number
  scheduleMode: 'static' | 'flexible'
  reasonCodes: ProgramReasonCode[]
  rationale: string | null
  stressDistributionReason?: string
  comparedToPrevious?: {
    previousFrequency: number
    frequencyChange: 'same' | 'increased' | 'decreased'
    changeReason?: string
  }
}

/**
 * Change summary for regenerate/adjust flows
 */
export interface ChangeExplanation {
  changed: boolean
  reasonCodes: ChangeReasonCode[]
  majorReasons: string[]      // Resolved human-readable reasons
  preservedReasons?: string[] // What stayed the same and why
  comparedToVersion?: string  // ID of previous program version
}

/**
 * Top-level program explanation metadata
 * Attached to AdaptiveProgram during generation
 */
export interface ProgramExplanationMetadata {
  // Summary section
  summary: {
    primaryGoalReason: string
    scheduleReason?: string
    progressionReason?: string
    recoveryReason?: string
  }
  
  // Week structure
  weekStructure: WeekStructureExplanation
  
  // Per-session explanations
  sessionExplanations: SessionExplanation[]
  
  // Change tracking (for regenerate)
  changeExplanation?: ChangeExplanation
  
  // Metadata
  generatedAt: string
  dataConfidence: 'none' | 'low' | 'medium' | 'high'
  trustedWorkoutCount: number
}

