// =============================================================================
// HELPER FUNCTIONS
// =============================================================================

/**
 * Resolve reason codes to a single short explanation string
 */
export function resolveReasonCodesToText(
  codes: ProgramReasonCode[],
  maxReasons: number = 2
): string {
  if (codes.length === 0) return ''
  
  // Prioritize the most important reasons
  const priorityOrder: ProgramReasonCode[] = [
    'primary_goal_direct',
    'weak_point_support',
    'limiter_support',
    'progression_advance',
    'fatigue_high_reduce_volume',
    'joint_stress_downrank',
    'skill_transfer_priority',
  ]
  
  // Sort by priority
  const sorted = [...codes].sort((a, b) => {
    const aIdx = priorityOrder.indexOf(a)
    const bIdx = priorityOrder.indexOf(b)
    if (aIdx === -1 && bIdx === -1) return 0
    if (aIdx === -1) return 1
    if (bIdx === -1) return -1
    return aIdx - bIdx
  })
  
  const topReasons = sorted.slice(0, maxReasons)
  return topReasons.map(code => PROGRAM_REASON_TEXT[code]).join('. ')
}

/**
 * Resolve session reason codes to text
 */
export function resolveSessionReasonCodesToText(
  codes: SessionReasonCode[],
  maxReasons: number = 1
): string {
  if (codes.length === 0) return ''
  const topReasons = codes.slice(0, maxReasons)
  return topReasons.map(code => SESSION_REASON_TEXT[code]).join('. ')
}

/**
 * Resolve change reason codes to text
 */
export function resolveChangeReasonCodesToText(
  codes: ChangeReasonCode[]
): string[] {
  return codes
    .filter(code => code !== 'first_generation')
    .map(code => CHANGE_REASON_TEXT[code])
}

/**
 * Check if explanation metadata is valid and grounded
 */
export function validateExplanationMetadata(
  metadata: Partial<ProgramExplanationMetadata>
): { isValid: boolean; issues: string[] } {
  const issues: string[] = []
  
  if (!metadata.summary?.primaryGoalReason) {
    issues.push('Missing primary goal reason')
  }
  
  if (!metadata.weekStructure) {
    issues.push('Missing week structure explanation')
  }
  
  if (!metadata.sessionExplanations || metadata.sessionExplanations.length === 0) {
    issues.push('Missing session explanations')
  }
  
  // Check that reason codes are valid
  metadata.sessionExplanations?.forEach((session, idx) => {
    if (!session.reasonCodes || session.reasonCodes.length === 0) {
      issues.push(`Session ${idx + 1} has no reason codes`)
    }
  })
  
  return {
    isValid: issues.length === 0,
    issues,
  }
}
